 |default_width= 250
}}}}
| caption3 = 

| image4   = {{#invoke:Infobox mapframe|auto}}
| caption4 = {{#invoke:Infobox mapframe|autocaption}}

| label1 = Alternative&nbsp;name
| class1 = nickname
| data1 = {{{other_name|{{{alternate_name|}}}}}}

